import { useState, useCallback } from 'react';
import { VENUE_TYPES } from '../constants/matchVenues';

export function useGameModals(pushNavigationState, removeFromNavigationStack) {
  // Pending goal state management
  const [pendingGoal, setPendingGoal] = useState(null);
  
  const [modals, setModals] = useState({
    fieldPlayer: {
      isOpen: false,
      type: null, // 'player'
      target: null, // position key
      playerName: '',
      sourcePlayerId: null,
      availablePlayers: [],
      showPositionOptions: false
    },
    substitute: {
      isOpen: false,
      playerId: null,
      playerName: '',
      isCurrentlyInactive: false,
      canSetAsNextToGoIn: false,
      canChangeNextPosition: false,
      availableNextPositions: [],
      showPositionSelection: false
    },
    substituteSelection: {
      isOpen: false,
      fieldPlayerName: '',
      fieldPlayerId: null,
      fieldPlayerPosition: null,
      availableSubstitutes: []
    },
    goalie: {
      isOpen: false,
      currentGoalieName: '',
      availablePlayers: []
    },
    scoreEdit: {
      isOpen: false
    },
    undoConfirm: {
      isOpen: false
    },
    goalScorer: {
      isOpen: false,
      eventId: null,
      team: VENUE_TYPES.HOME,
      mode: 'new', // 'new', 'correct', 'view'
      matchTime: '00:00',
      periodNumber: 1,
      existingGoalData: null
    }
  });

  const closeModal = useCallback((modalType) => {
    setModals(prev => ({
      ...prev,
      [modalType]: {
        ...prev[modalType],
        isOpen: false
      }
    }));
  }, []);

  const openModal = useCallback((modalType, modalData = {}) => {
    setModals(prev => ({
      ...prev,
      [modalType]: {
        ...prev[modalType],
        isOpen: true,
        ...modalData
      }
    }));

    // Browser back navigation integration
    if (pushNavigationState) {
      pushNavigationState(() => {
        closeModal(modalType);
      });
    }
  }, [pushNavigationState, closeModal]);

  const closeModalWithNavigation = useCallback((modalType) => {
    closeModal(modalType);
    if (removeFromNavigationStack) {
      removeFromNavigationStack();
    }
  }, [closeModal, removeFromNavigationStack]);

  const closeAllModals = useCallback(() => {
    setModals(prev => {
      const newModals = { ...prev };
      Object.keys(newModals).forEach(key => {
        newModals[key] = { ...newModals[key], isOpen: false };
      });
      return newModals;
    });
  }, []);

  // Specific modal operations for convenience
  const openFieldPlayerModal = useCallback((modalData) => {
    openModal('fieldPlayer', modalData);
  }, [openModal]);

  const closeFieldPlayerModal = useCallback(() => {
    closeModal('fieldPlayer');
  }, [closeModal]);

  const openSubstituteModal = useCallback((modalData) => {
    openModal('substitute', modalData);
  }, [openModal]);

  const closeSubstituteModal = useCallback(() => {
    closeModal('substitute');
  }, [closeModal]);

  const openGoalieModal = useCallback((modalData) => {
    openModal('goalie', modalData);
  }, [openModal]);

  const closeGoalieModal = useCallback(() => {
    closeModal('goalie');
  }, [closeModal]);

  const openScoreEditModal = useCallback(() => {
    openModal('scoreEdit');
  }, [openModal]);

  const closeScoreEditModal = useCallback(() => {
    closeModal('scoreEdit');
  }, [closeModal]);

  const openUndoConfirmModal = useCallback(() => {
    openModal('undoConfirm');
  }, [openModal]);

  const closeUndoConfirmModal = useCallback(() => {
    closeModal('undoConfirm');
  }, [closeModal]);

  const openGoalScorerModal = useCallback((modalData) => {
    openModal('goalScorer', modalData);
  }, [openModal]);

  const closeGoalScorerModal = useCallback(() => {
    closeModal('goalScorer');
  }, [closeModal]);

  const openSubstituteSelectionModal = useCallback((modalData) => {
    openModal('substituteSelection', modalData);
  }, [openModal]);

  const closeSubstituteSelectionModal = useCallback(() => {
    closeModal('substituteSelection');
  }, [closeModal]);

  // Pending goal management functions
  const setPendingGoalData = useCallback((goalData) => {
    setPendingGoal(goalData);
  }, []);

  const getPendingGoalData = useCallback(() => {
    return pendingGoal;
  }, [pendingGoal]);

  const clearPendingGoal = useCallback(() => {
    setPendingGoal(null);
  }, []);

  return {
    modals,
    // Generic modal operations
    openModal,
    closeModal,
    closeModalWithNavigation,
    closeAllModals,
    // Specific modal operations
    openFieldPlayerModal,
    closeFieldPlayerModal,
    openSubstituteModal,
    closeSubstituteModal,
    openSubstituteSelectionModal,
    closeSubstituteSelectionModal,
    openGoalieModal,
    closeGoalieModal,
    openScoreEditModal,
    closeScoreEditModal,
    openUndoConfirmModal,
    closeUndoConfirmModal,
    openGoalScorerModal,
    closeGoalScorerModal,
    // Pending goal operations
    setPendingGoalData,
    getPendingGoalData,
    clearPendingGoal
  };
}
